def numIslands(grid):
    if not grid: return 0
    m, n, res = len(grid), len(grid[0]), 0
    def dfs(r, c):
        if 0<=r<m and 0<=c<n and grid[r][c] == "1":
            grid[r][c] = "0"
            for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]: dfs(r+dr, c+dc)
    for r in range(m):
        for c in range(n):
            if grid[r][c] == "1": res += 1; dfs(r, c)
    return res

